namespace sv_83a0267e24c4463581a1cf642c8da78d.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// Interactive components subscribe to OnThemeChanged to re-render
/// when any other component mutates the theme.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme => _theme;
    public string AccentColor => _accentColor;

    public event Action? OnThemeChanged;

    public void SetTheme(ThemeMode theme)
    {
        if (_theme == theme) return;
        _theme = theme;
        OnThemeChanged?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (_accentColor == color) return;
        _accentColor = color;
        OnThemeChanged?.Invoke();
    }

    public void SetAll(ThemeMode theme, string accentColor)
    {
        bool changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) OnThemeChanged?.Invoke();
    }
}

@* Interactive island — lives in the static header but runs on the circuit *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator badge rounded-pill"
      style="background-color: @ThemeService.AccentColor; color: white;">
    @Icon @ThemeService.Theme
</span>

@code {
    private string Icon => ThemeService.Theme switch
    {
        ThemeMode.Light  => "☀️",
        ThemeMode.Dark   => "🌙",
        _                => "💻"
    };

    protected override void OnInitialized()
        => ThemeService.OnThemeChanged += StateHasChanged;

    public void Dispose()
        => ThemeService.OnThemeChanged -= StateHasChanged;
}

@* Quick toggle that cycles Light → Dark → System *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-light" @onclick="CycleTheme"
        title="Current: @ThemeService.Theme — click to cycle">
    @Icon
</button>

@code {
    private string Icon => ThemeService.Theme switch
    {
        ThemeMode.Light  => "☀️",
        ThemeMode.Dark   => "🌙",
        _                => "💻"
    };

    private void CycleTheme()
    {
        var next = ThemeService.Theme switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            _                => ThemeMode.Light
        };
        ThemeService.SetTheme(next);
    }

    protected override void OnInitialized()
        => ThemeService.OnThemeChanged += StateHasChanged;

    public void Dispose()
        => ThemeService.OnThemeChanged -= StateHasChanged;
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 480px;">
    <h5>Theme</h5>
    <div class="btn-group mb-3" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <button class="btn @(mode == ThemeService.Theme ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeService.SetTheme(mode)">
                @mode
            </button>
        }
    </div>

    <h5>Accent Color</h5>
    <input type="color" class="form-control form-control-color mb-3"
           value="@ThemeService.AccentColor"
           @onchange="OnColorChanged" />

    <p class="text-muted mb-0">
        Current: <strong>@ThemeService.Theme</strong> ·
        Accent: <span style="color: @ThemeService.AccentColor; font-weight: bold;">
            @ThemeService.AccentColor
        </span>
    </p>
</div>

@code {
    private void OnColorChanged(ChangeEventArgs e)
        => ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");

    protected override void OnInitialized()
        => ThemeService.OnThemeChanged += StateHasChanged;

    public void Dispose()
        => ThemeService.OnThemeChanged -= StateHasChanged;
}

